	RzBinObject *o = bf->o;

	int va = VA_TRUE; // XXX relocs always vaddr?
	char *relname = NULL;
	bool demangle = rz_config_get_b(core->config, "bin.demangle");

	RzBinRelocStorage *relocs = rz_bin_object_patch_relocs(bf, o);

