3920	 * \param dh_orig Name of the debug handler, e.g. "esil"
3921	 */
3922	RZ_API bool rz_core_analysis_everything(RzCore *core, bool experimental, char *dh_orig) {
3923		bool didAap = false;
3924		const char *notify = NULL;
3925		ut64 curseek = core->offset;
3926		bool cfg_debug = rz_config_get_b(core->config, "cfg.debug");
3927		bool plugin_supports_esil = core->analysis->cur->esil;
3928		bool is_apple = is_apple_target(core);
3929	
3930		if (rz_str_startswith(rz_config_get(core->config, "bin.lang"), "go")) {
3931			rz_core_notify_done(core, "Find function and symbol names from golang binaries");
3932			if (rz_core_analysis_recover_golang_functions(core)) {
3933				rz_core_analysis_resolve_golang_strings(core);
3934			}
3935			rz_core_task_yield(&core->tasks);
3936			if (rz_cons_is_breaked()) {
3937				return false;
3938			}
3939		}
3940	
3941		if (is_apple) {
3942			notify = "Recover all Objective-C selector stub names";
3943			rz_core_notify_begin(core, "%s", notify);
3944			rz_core_analysis_objc_stubs(core); // "aalos"
3945			rz_core_notify_done(core, "%s", notify);
3946			rz_core_task_yield(&core->tasks);
3947			if (rz_cons_is_breaked()) {
3948				return false;
3949			}
3950		}
3951	
3952		rz_core_task_yield(&core->tasks);
3953		if (!cfg_debug) {
3954			if (dh_orig && strcmp(dh_orig, "esil")) {
3955				rz_config_set(core->config, "dbg.backend", "esil");
3956				rz_core_task_yield(&core->tasks);
3957			}
3958		}
3959		int c = rz_config_get_i(core->config, "analysis.calls");
3960		rz_config_set_i(core->config, "analysis.calls", 1);
3961		ut64 t = rz_num_math(core->num, "$S");
3962		rz_core_seek(core, t, true);
3963		if (rz_cons_is_breaked()) {
3964			return false;
3965		}
3966	
3967		notify = "Analyze function calls";
3968		rz_core_notify_begin(core, "%s", notify);
3969		(void)rz_core_analysis_calls(core, false); // "aac"
3970		rz_core_seek(core, curseek, true);
3971		rz_core_notify_done(core, "%s", notify);
3972		rz_core_task_yield(&core->tasks);
3973		if (rz_cons_is_breaked()) {
3974			return false;
3975		}
3976	
3977		if (!rz_str_startswith(rz_config_get(core->config, "asm.arch"), "x86")) {
3978			notify = "find and analyze function preludes";
3979			rz_core_notify_begin(core, "%s", notify);
3980			(void)rz_core_search_preludes(core, false); // "aap"
3981			didAap = true;
3982			rz_core_notify_done(core, "%s", notify);
3983			rz_core_task_yield(&core->tasks);
3984			if (rz_cons_is_breaked()) {
3985				return false;
3986			}
3987		}
3988	
3989		notify = "Analyze len bytes of instructions for references";
3990		rz_core_notify_begin(core, "%s", notify);
3991		(void)rz_core_analysis_refs(core, 0); // "aar"
3992		rz_core_notify_done(core, "%s", notify);
3993		rz_core_task_yield(&core->tasks);
3994		if (rz_cons_is_breaked()) {
3995			return false;
3996		}
3997	
3998		if (is_apple) {
3999			notify = "Check for objc references";
4000			rz_core_notify_begin(core, "%s", notify);
4001			rz_core_analysis_objc_refs(core, true); // "aalor"
4002			rz_core_notify_done(core, "%s", notify);
4003		}
4004		rz_core_task_yield(&core->tasks);
4005	
4006		rz_config_set_i(core->config, "analysis.calls", c);
4007		rz_core_task_yield(&core->tasks);
4008		if (rz_cons_is_breaked()) {
4009			return false;
4010		}
4011	
4012		if (!rz_asm_is_arch(core->rasm, "x86") &&
4013			!rz_asm_is_arch(core->rasm, "hexagon")) {
4014			rz_core_analysis_value_pointers(core, RZ_OUTPUT_MODE_STANDARD);
4015			rz_core_task_yield(&core->tasks);
4016			bool pcache = rz_config_get_b(core->config, "io.pcache");
4017			rz_config_set_b(core->config, "io.pcache", false);
