	case R_386_COPY: ADD(32, 0, "R_386_COPY", RZ_RELOC_BASE_UNKNOWN); // copy symbol at runtime
	case R_386_IRELATIVE: IFCN(32, "R_386_IRELATIVE");
	case R_386_32PLT: ADD(32, 0, "R_386_32PLT", RZ_RELOC_BASE_PLT_SYMBOL);
